using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public required string Text { get; set; }

    /// <summary>
    /// Maximum number of sentences to include in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 50)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalSentenceCount { get; set; }
    public int SummarySentenceCount { get; set; }
}

using DocSummary.Models;

namespace DocSummary.Services;

public interface IDocumentSummaryService
{
    SummarizeResponse Summarize(string text, int maxSentences);
}

using System.Text.RegularExpressions;
using DocSummary.Models;

namespace DocSummary.Services;

/// <summary>
/// Extractive summarization using TF-based sentence scoring.
/// Selects the highest-scoring sentences while preserving original order.
/// </summary>
public partial class DocumentSummaryService : IDocumentSummaryService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a","an","the","and","or","but","is","are","was","were","be","been",
        "being","have","has","had","do","does","did","will","would","shall",
        "should","may","might","must","can","could","i","me","my","we","our",
        "you","your","he","him","his","she","her","it","its","they","them",
        "their","this","that","these","those","of","in","to","for","with",
        "on","at","from","by","about","as","into","through","during","before",
        "after","above","below","between","out","off","over","under","then",
        "so","no","not","only","very","just","if","up","also","each","which",
        "when","what","where","who","whom","how","all","both","few","more",
        "most","other","some","such","than","too","s","t","don","re","ve",
        "ll","d","m"
    };

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceSplitter();

    [GeneratedRegex(@"[^\w\s]")]
    private static partial Regex PunctuationStripper();

    public SummarizeResponse Summarize(string text, int maxSentences)
    {
        var sentences = SentenceSplitter()
            .Split(text.Trim())
            .Where(s => !string.IsNullOrWhiteSpace(s))
            .ToList();

        if (sentences.Count <= maxSentences)
        {
            return new SummarizeResponse
            {
                Summary = string.Join(" ", sentences),
                OriginalSentenceCount = sentences.Count,
                SummarySentenceCount = sentences.Count
            };
        }

        // Tokenize each sentence and compute word frequencies (excluding stop words)
        var tokenized = sentences
            .Select(s => Tokenize(s))
            .ToList();

        var wordFrequency = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var tokens in tokenized)
        {
            foreach (var token in tokens)
            {
                if (!StopWords.Contains(token))
                    wordFrequency[token] = wordFrequency.GetValueOrDefault(token) + 1;
            }
        }

        // Score each sentence by the sum of its word frequencies
        var scored = tokenized
            .Select((tokens, index) => (
                Index: index,
                Score: tokens.Where(t => !StopWords.Contains(t))
                             .Sum(t => wordFrequency.GetValueOrDefault(t))
            ))
            .OrderByDescending(x => x.Score)
            .Take(maxSentences)
            .OrderBy(x => x.Index) // preserve original order
            .ToList();

        var summary = string.Join(" ", scored.Select(x => sentences[x.Index]));

        return new SummarizeResponse
        {
            Summary = summary,
            OriginalSentenceCount = sentences.Count,
            SummarySentenceCount = scored.Count
        };
    }

    private static List<string> Tokenize(string sentence)
    {
        var cleaned = PunctuationStripper().Replace(sentence, "");
        return cleaned
            .Split(' ', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .Select(w => w.ToLowerInvariant())
            .ToList();
    }
}

